 1	import React from 'react';
 2	
 3	import { tickLabels } from '@kubevirt-utils/components/Charts/ChartLabels/styleOverrides';
 4	import useResponsiveCharts from '@kubevirt-utils/components/Charts/hooks/useResponsiveCharts';
 5	import {
 6	  Chart,
 7	  ChartArea,
 8	  ChartAxis,
 9	  ChartGroup,
10	  ChartVoronoiContainer,
11	} from '@patternfly/react-charts';
12	import chart_color_black_200 from '@patternfly/react-tokens/dist/esm/chart_color_black_200';
13	import chart_color_blue_100 from '@patternfly/react-tokens/dist/esm/chart_color_blue_100';
14	
15	import useXAxisTicks from '../utils/hooks/useXAxisTicks';
16	import useYAxisTicks from '../utils/hooks/useYAxisTicks';
17	import { MetricChartProps } from '../utils/types';
18	import { formatPopoverLabel, getLabelUnit } from '../utils/utils';
19	
20	import './MetricChart.scss';
21	
22	const MetricChart: React.FC<MetricChartProps> = ({ metric, metricChartData }) => {
23	  const { chartData, domain, unit } = metricChartData;
24	  const { height, ref, width } = useResponsiveCharts();
25	  const displayUnit = getLabelUnit(metric, unit);
26	  const [xAxisTicks, xAxisTickFormat] = useXAxisTicks(chartData);
27	  const [yAxisTickValues, yAxisTickFormat] = useYAxisTicks(metricChartData);
28	
29	  return (
30	    <div className="overview-metric-chart" ref={ref}>
31	      <Chart
32	        containerComponent={
33	          <ChartVoronoiContainer constrainToVisibleArea labels={formatPopoverLabel(displayUnit)} />
34	        }
35	        domain={domain}
36	        height={height}
37	        padding={{ bottom: 35, left: 100, right: 10, top: 35 }}
38	        scale={{ x: 'time', y: 'linear' }}
39	        width={width}
40	      >
41	        <ChartAxis
42	          style={{
43	            grid: {
44	              stroke: chart_color_black_200.value,
45	            },
46	            tickLabels,
47	          }}
48	          axisComponent={<></>}
49	          dependentAxis
50	          tickFormat={yAxisTickFormat(metric, unit)}
51	          tickValues={yAxisTickValues}
52	        />
53	        <ChartAxis
54	          style={{
55	            axis: {
56	              stroke: chart_color_black_200.value,
57	            },
58	            tickLabels,
59	          }}
60	          fixLabelOverlap
61	          tickFormat={xAxisTickFormat}
62	          tickValues={xAxisTicks}
63	        />
64	        <ChartGroup>
65	          <ChartArea
66	            style={{
67	              data: {
68	                stroke: chart_color_blue_100.value,
69	              },
70	            }}
71	            data={chartData}
72	          />
73	        </ChartGroup>
74	      </Chart>
75	    </div>
76	  );
77	};
78	
79	export default MetricChart;

